  1	import * as React from 'react';
  2	import { DRPlacementControlModel } from '@odf/shared';
  3	import { StatusBox } from '@odf/shared/generic';
  4	import { ModalBody, ModalFooter } from '@odf/shared/modals/Modal';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import { getErrorMessage } from '@odf/shared/utils';
  7	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
  8	import { TFunction } from 'react-i18next';
  9	import {
 10	  Modal,
 11	  Button,
 12	  ModalVariant,
 13	  ButtonType,
 14	  ButtonVariant,
 15	  Alert,
 16	  AlertVariant,
 17	} from '@patternfly/react-core';
 18	import { DRActionType } from '../../../constants';
 19	import {
 20	  ApplicationProps,
 21	  PlacementControlProps,
 22	  FailoverRelocateModalBody,
 23	} from './failover-relocate-modal-body';
 24	
 25	export enum ModalFooterStatus {
 26	  INITIAL = 'intial',
 27	  INPROGRESS = 'inProgress',
 28	}
 29	
 30	const getModalText = (t: TFunction) => ({
 31	  [DRActionType.FAILOVER]: {
 32	    title: t('Failover application'),
 33	    description: t(
 34	      'Failing over force stops active replication and deploys your application on the selected target cluster. Recommended only when the primary cluster is down.'
 35	    ),
 36	  },
 37	  [DRActionType.RELOCATE]: {
 38	    title: t('Relocate application'),
 39	    description: t(
 40	      'Relocating terminates your application on its current cluster, syncs its most recent snapshot to the selected target cluster, and then brings up your application.'
 41	    ),
 42	  },
 43	});
 44	
 45	export const FailoverRelocateModal: React.FC<FailoverRelocateModalProps> = (
 46	  props
 47	) => {
 48	  const { applicationNamespace, action, isOpen, loaded, loadError, close } =
 49	    props;
 50	
 51	  const { t } = useCustomTranslation();
 52	  const modalText = getModalText(t)[action];
 53	  const [errorMessage, setErrorMessage] = React.useState('');
 54	  const [footerStatus, setFooterStatus] = React.useState(
 55	    ModalFooterStatus.INITIAL
 56	  );
 57	  const [placementControl, setPlacementControl] =
 58	    React.useState<PlacementControlProps>({});
 59	  const [canInitiate, setCanInitiate] = React.useState(false);
 60	
 61	  const onClick = () => {
 62	    setFooterStatus(ModalFooterStatus.INPROGRESS);
 63	    // Preferred cluster and failover cluster should not be the same for failover and relocate.
 64	    const patch = [
 65	      {
 66	        op: 'replace',
 67	        path: '/spec/action',
 68	        value: action,
 69	      },
 70	      {
 71	        op: 'replace',
 72	        path: '/spec/failoverCluster',
 73	        value:
 74	          action === DRActionType.FAILOVER
 75	            ? placementControl?.targetClusterName
 76	            : placementControl?.primaryClusterName,
 77	      },
 78	      {
 79	        op: 'replace',
 80	        path: '/spec/preferredCluster',
 81	        value:
 82	          action === DRActionType.FAILOVER
 83	            ? placementControl?.primaryClusterName
 84	            : placementControl?.targetClusterName,
 85	      },
 86	    ];
 87	    k8sPatch({
 88	      model: DRPlacementControlModel,
 89	      resource: {
 90	        metadata: {
 91	          name: placementControl?.drPlacementControlName,
 92	          namespace: applicationNamespace,
 93	        },
 94	      },
 95	      data: patch,
 96	    })
 97	      .then(() => {
 98	        close();
 99	      })
100	      .catch((error) => {
101	        setFooterStatus(ModalFooterStatus.INITIAL);
102	        setErrorMessage(getErrorMessage(error));
103	      });
104	  };
105	
106	  return (
107	    <Modal
108	      title={modalText.title}
109	      description={modalText.description}
110	      isOpen={isOpen}
111	      onClose={close}
112	      variant={ModalVariant.medium}
113	    >
114	      <ModalBody>
115	        {loaded && !loadError ? (
116	          <>
117	            <FailoverRelocateModalBody
118	              {...props}
119	              canInitiate={canInitiate}
120	              setCanInitiate={setCanInitiate}
121	              setPlacement={setPlacementControl}
122	            />
123	
124	            {(!!errorMessage || !!loadError) && (
125	              <Alert
126	                title={errorMessage || getErrorMessage(loadError)}
127	                variant={AlertVariant.danger}
128	                isInline
129	              />
130	            )}
131	          </>
132	        ) : (
133	          <StatusBox loaded={loaded} loadError={loadError} />
134	        )}
135	      </ModalBody>
136	      <ModalFooter>
137	        <Button
138	          key="modal-cancel-action"
139	          id={'modal-cancel-action'}
140	          data-test-id={'modal-cancel-action'}
141	          type={ButtonType.button}
142	          variant={ButtonVariant.link}
143	          onClick={close}
144	        >
145	          {t('Cancel')}
146	        </Button>
147	        <Button
148	          key="modal-intiate-action"
149	          id={'modal-intiate-action'}
150	          data-test-id={'modal-intiate-action'}
151	          type={ButtonType.button}
152	          variant={ButtonVariant.primary}
153	          isDisabled={
154	            !canInitiate ||
155	            !!loadError ||
156	            footerStatus === ModalFooterStatus.INPROGRESS
157	          }
158	          isLoading={footerStatus === ModalFooterStatus.INPROGRESS}
159	          onClick={onClick}
160	        >
161	          {footerStatus === ModalFooterStatus.INITIAL
162	            ? t('Initiate')
163	            : t('Initiating')}
164	        </Button>
165	      </ModalFooter>
166	    </Modal>
167	  );
168	};
169	
170	type FailoverRelocateModalProps = ApplicationProps & {
171	  isOpen: boolean;
172	  close?: () => void;
173	};

